SELECT COUNT(*) AS active_instances
FROM microcontroller_instances
WHERE status = 'active';

SELECT COUNT(DISTINCT mcu_model) AS model_count
FROM microcontrollers
WHERE manufacturer = 'STMicroelectronics';

SELECT serial_number, status
FROM microcontroller_instances
WHERE status = 'active';

SELECT mcu_model, last_updated
FROM microcontrollers
ORDER BY last_updated DESC;

SELECT COUNT(*) AS instance_count
FROM microcontroller_instances
WHERE mcu_id = (SELECT mcu_id FROM microcontrollers WHERE mcu_model = 'STM32F103');
